context.buffer = context.buffer || "";

// 1. Convert incoming payload to string safely (handles Unicode/Emojis)
let input = "";
try {
    input = (Buffer.isBuffer(msg.payload)) ? msg.payload.toString('utf8') : msg.payload;
} catch (e) {
    node.error("Encoding error: " + e.message);
    return null;
}

// Ignore exit code objects
if (typeof input !== 'string') return null;

// 2. Accumulate the input into our buffer
context.buffer += input;

// 3. Process the buffer if it's getting large or has a newline
if (context.buffer.length > 500 || input.includes('\n')) {
    const LIMIT = 950; // Safety limit for Debug sidebar

    // While the buffer is larger than our safety limit, slice it
    while (context.buffer.length >= LIMIT) {
        let chunk = context.buffer.substring(0, LIMIT);
        context.buffer = context.buffer.substring(LIMIT);

        node.send({ payload: chunk, topic: "python_log_chunk" });
    }

    // If the process ended (input was small) or we have a complete line,
    // send the remainder of the buffer
    if (input.includes('\n') && context.buffer.length > 0) {
        node.send({ payload: context.buffer, topic: "python_log_line" });
        context.buffer = ""; // Clear buffer after sending full line
    }
}

return null;

